import com.yomahub.liteflow.core.NodeComponent;
import com.yomahub.liteflow.slot.DefaultContext;

public class Demo extends NodeComponent {
    @Override
    public void process() throws Exception {
        DefaultContext ctx = this.getFirstContextBean();
        // 根据 nodeId 写入不同的数据来验证是否真的执行了对应节点
        ctx.setData(this.getNodeId(), "executed by " + this.getNodeId());
        System.out.println("Executing node: " + this.getNodeId());
    }
}


